// services/hasuraClient.js

const HASURA_ENDPOINT = 'http://localhost:8080/v1/graphql';
// Tối ưu hơn: const HASURA_ENDPOINT = process.env.NEXT_PUBLIC_HASURA_ENDPOINT;

/**
 * Hàm gọi API chung đến Hasura
 * @param {string} query - Chuỗi GraphQL query hoặc mutation
 * @param {object} variables - Các tham số truyền vào (nếu có)
 */
export async function fetchGraphQL(query, variables = {}) {
  try {
    const response = await fetch(HASURA_ENDPOINT, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        // 'x-hasura-admin-secret': process.env.HASURA_ADMIN_SECRET // Thêm token nếu có
      },
      body: JSON.stringify({
        query,
        variables,
      }),
      // cache: 'no-store' // (Tuỳ chọn ở Next.js)
    });

    const result = await response.json();

    if (result.errors) {
      console.error('Lỗi từ Hasura GraphQL:', result.errors);
      throw new Error('Không thể fetch dữ liệu từ Hasura');
    }

    return result.data;
  } catch (error) {
    console.error('Lỗi hệ thống khi gọi API:', error);
    throw error;
  }
}